;ACME
; =====================================================================
; x16lib :: dist/x16lib_blob.asm -- the whole library as one binary
; =====================================================================
; Assembled by dist.ps1 into dist/x16lib.bin (raw, org X16LIB_ORG) so
; that ca65, 64tass and KickAssembler programs can use the library
; without an ACME source port: they include the binary at X16LIB_ORG
; and call the routines through the generated x16lib.inc bindings.
;
; The org is fixed and part of the binding ABI: dist.ps1 derives every
; exported address from this exact build's symbol list, so the blob and
; the bindings can never drift apart -- but a blob from one dist build
; must only be used with the includes generated by that same build.
;
; The first six bytes are a signature ("X16L", version, module byte)
; a loader can sanity-check at run time.
; =====================================================================

!cpu 65c02
!source "x16.asm"

X16_USE_VERA = 1
X16_USE_SCREEN = 1
X16_USE_PALETTE = 1
X16_USE_TILE = 1
X16_USE_SPRITE = 1
X16_USE_VERAFX = 1
X16_USE_IRQ = 1
X16_USE_PSG = 1
X16_USE_YM = 1
X16_USE_PCM = 1
X16_USE_PCM_STREAM = 1
X16_USE_INPUT = 1
X16_USE_BANK = 1
X16_USE_BANKALLOC = 1
X16_USE_MEM = 1
X16_USE_LOAD = 1
X16_USE_DOS = 1
X16_USE_BMX = 1
X16_USE_MATH = 1
X16_USE_CLIP = 1
X16_USE_BUFFERS = 1
X16_USE_ADPCM = 1
X16_USE_ZX0 = 1
X16_USE_TSC = 1
X16_USE_FIXED = 1
X16_USE_COLLIDE = 1
X16_USE_BITS = 1
X16_USE_NUMBER = 1
X16_USE_INT16 = 1
X16_USE_INT32 = 1
X16_USE_FLOAT = 1

!ifndef X16LIB_ORG { X16LIB_ORG = $5800 }

* = X16LIB_ORG

x16lib_magic   !text "X16L"
x16lib_version !byte 1
x16lib_flags   !byte 0

!source "x16_code.asm"

x16lib_end
!if x16lib_end > $9F00 {
    !error "library blob runs past $9EFF into the I/O area"
}
